import{_ as a,o as i,c as o,ai as r,dK as n,dL as t,dM as s,dN as l,dO as p,dP as c,dQ as d,dR as u,dS as m,dT as g,dU as _,dV as v,dW as h,dX as f}from"./chunks/framework.DIUhWiTt.js";const T=JSON.parse('{"title":"Limit overrun race conditions","description":"","frontmatter":{},"headers":[],"relativePath":"notas/PortSwigger/14.Race conditions/1.Limit overrun race conditions/1.Limit overrun race conditions.md","filePath":"notas/PortSwigger/14.Race conditions/1.Limit overrun race conditions/1.Limit overrun race conditions.md"}'),b={name:"notas/PortSwigger/14.Race conditions/1.Limit overrun race conditions/1.Limit overrun race conditions.md"};function L(P,e,A,q,z,S){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="limit-overrun-race-conditions" tabindex="-1">Limit overrun race conditions <a class="header-anchor" href="#limit-overrun-race-conditions" aria-label="Permalink to “Limit overrun race conditions”">​</a></h1><p>El tipo más conocido de condición de carrera le permite superar algún tipo de límite impuesto por la lógica empresarial de la aplicación.</p><p><img src="'+n+'" alt="[20251019233741.png]"></p><p>Por ejemplo, considere una tienda en línea que le permite introducir un código promocional durante el proceso de pago para obtener un descuento único en su pedido. Para aplicar este descuento, la aplicación puede realizar los siguientes pasos de alto nivel:</p><ul><li>Comprobar que aún no ha utilizado este código.</li><li>Aplicar el descuento al total del pedido.</li><li>Actualizar el registro en la base de datos para reflejar el hecho de que ahora ha utilizado este código. Si más adelante intenta reutilizar este código, las comprobaciones iniciales realizadas al comienzo del proceso deberían impedirle hacerlo:</li></ul><p><img src="'+t+'" alt="[20251019233718.png]"></p><p>Ahora considere qué sucedería si un usuario que nunca ha aplicado este código de descuento antes intentara aplicarlo dos veces casi exactamente al mismo tiempo:</p><p><img src="'+s+'" alt="[20251019233956.png]"></p><p>Existen muchas variantes de este tipo de ataque, entre ellas:</p><ul><li>Canjear una tarjeta de regalo varias veces</li><li>Calificar un producto varias veces</li><li>Retirar o transferir efectivo en exceso del saldo de su cuenta</li><li>Reutilización de una única solución CAPTCHA</li><li>Evitar un límite de velocidad anti-fuerza bruta</li></ul><h2 id="lab" tabindex="-1">LAB <a class="header-anchor" href="#lab" aria-label="Permalink to “LAB”">​</a></h2><p><img src="'+l+'" alt="[20251019231801.png]"></p><p>En el sitio web tenemos un cupon de descuento.</p><p><img src="'+p+'" alt="[20251019232005.png]"></p><p>En el que podemos aplicar para poder comprar algunos artículos, pero observamos que solo tenemos $50 de saldo.</p><p><img src="'+c+'" alt="[20251019232155.png]"></p><p>Al aplicar un descuento o cupón vemos que nos hace una reducción del total</p><p><img src="'+d+'" alt="[20251019232432.png]"></p><p>Lo que se puede realizar es un envio masivo de la solicitar al agregar el cupón, de manera paralela.</p><p><img src="'+u+'" alt="[20251019232545.png]"></p><p>Para ello podemos crear un grupo</p><p><img src="'+m+'" alt="[20251019232616.png]"></p><p>Y duplicar la solicitud que agrega el cupón</p><p><img src="'+g+'" alt="[20251019232708.png]"></p><p><img src="'+_+'" alt="[20251019232729.png]"></p><p>Al duplicar un total de 30 solicitudes, elegimos la opción de <code>send group parallel</code>.</p><p><img src="'+v+'" alt="[20251019232828.png]"></p><p><img src="'+h+'" alt="[20251019232849.png]"></p><p>Al volver al panel de compra vemos que podemos comprar el articulo.</p><p><img src="'+f+'" alt="[20251019232403.png]"></p>',30)])])}const C=a(b,[["render",L]]);export{T as __pageData,C as default};
